import{_ as t,a as n,b as a,c as i,d as r,e as d}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as s,o as l,c as o,a2 as u}from"./chunks/framework.DnrXFDHb.js";const z=JSON.parse('{"title":"IP-Geolokalisierung und Benutzerverwaltung","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Other/ip-geolocation-and-user-management.md","filePath":"de-DE/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),h={name:"de-DE/Other/ip-geolocation-and-user-management.md"};function p(c,e,g,b,m,f){return l(),o("div",null,[...e[0]||(e[0]=[u('<h1 id="ip-geolokalisierung-und-benutzerverwaltung" tabindex="-1">IP-Geolokalisierung und Benutzerverwaltung <a class="header-anchor" href="#ip-geolokalisierung-und-benutzerverwaltung" aria-label="Permalink to &quot;IP-Geolokalisierung und Benutzerverwaltung&quot;">​</a></h1><p>Die IP-Geolokalisierung wandelt IP-Adressen aus Uploads, Login-Geräten und Protokollen in ungefähre Standorte um.</p><p>Nach der Einrichtung zeigt der Adminbereich Upload- und Zugriffsquellen verständlicher an. In der Benutzerverwaltung kannst du verdächtigen IPs Uploads sperren oder wieder erlauben.</p><h2 id="wo-einstellen" tabindex="-1">Wo einstellen <a class="header-anchor" href="#wo-einstellen" aria-label="Permalink to &quot;Wo einstellen&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Systemeinstellungen -&gt; Weitere Einstellungen -&gt; IP-Geolokalisierung</span></span></code></pre></div><p><img src="'+t+`" alt="IP-Geolokalisierung" loading="lazy"></p><h2 id="verfugbare-einstellungen" tabindex="-1">Verfügbare Einstellungen <a class="header-anchor" href="#verfugbare-einstellungen" aria-label="Permalink to &quot;Verfügbare Einstellungen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Einstellung</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Sprache der IP-Ortung</td><td>Sprache der angezeigten Standorte</td></tr><tr><td>MaxMind Account ID</td><td>Konto-ID für MaxMind GeoLite Web Service</td></tr><tr><td>MaxMind License Key</td><td>Lizenzschlüssel von MaxMind</td></tr><tr><td>Tencent Map Key</td><td>Nützlich für Adressen in Festlandchina</td></tr><tr><td>ipapi Key</td><td>APILayer-ipapi-Schlüssel mit mehrsprachiger Unterstützung</td></tr></tbody></table><p>Trage nur die Dienste ein, die du brauchst. Ohne Schlüssel versucht ImgBed integrierte kostenlose Quellen, die aber weniger stabil oder genau sein können.</p><h2 id="empfehlung-fur-deutsch" tabindex="-1">Empfehlung für Deutsch <a class="header-anchor" href="#empfehlung-fur-deutsch" aria-label="Permalink to &quot;Empfehlung für Deutsch&quot;">​</a></h2><p>Für deutsche oder mehrsprachige Standortanzeigen richte MaxMind ein und ergänze bei Bedarf ipapi für bessere mehrsprachige Ergebnisse.</p><h2 id="maxmind-einrichten" tabindex="-1">MaxMind einrichten <a class="header-anchor" href="#maxmind-einrichten" aria-label="Permalink to &quot;MaxMind einrichten&quot;">​</a></h2><p>MaxMind benötigt:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Suche die Account ID im MaxMind-Dashboard, erstelle einen License Key und trage beide Werte in ImgBed ein.</p><p><img src="`+n+'" alt="MaxMind-Konfiguration" loading="lazy"></p><h2 id="ipapi-einrichten" tabindex="-1">ipapi einrichten <a class="header-anchor" href="#ipapi-einrichten" aria-label="Permalink to &quot;ipapi einrichten&quot;">​</a></h2><p>Kopiere den API Key aus der ipapi-Konsole.</p><p><img src="'+a+'" alt="ipapi-Konfiguration" loading="lazy"></p><p>Füge ihn in ImgBed bei <code>ipapi Key</code> ein und speichere.</p><h2 id="benutzerverwaltung" tabindex="-1">Benutzerverwaltung <a class="header-anchor" href="#benutzerverwaltung" aria-label="Permalink to &quot;Benutzerverwaltung&quot;">​</a></h2><p>Die Benutzerverwaltung öffnest du oben im Adminbereich.</p><p><img src="'+i+'" alt="Benutzerverwaltung" loading="lazy"></p><p>Sie gruppiert Aktivitäten nach IP.</p><table tabindex="0"><thead><tr><th>Feld</th><th>Beschreibung</th></tr></thead><tbody><tr><td>IP</td><td>Quell-IP</td></tr><tr><td>Standort</td><td>Ungefährer Standort zur IP</td></tr><tr><td>Gesamte Upload-Größe</td><td>Summe der von dieser IP hochgeladenen Dateien</td></tr><tr><td>Anzahl Uploads</td><td>Anzahl der Uploads</td></tr><tr><td>Upload erlaubt</td><td>Deaktivieren, um neue Uploads dieser IP zu blockieren</td></tr></tbody></table><p>Öffne den Pfeil links, um Dateien dieser IP zu sehen: Name, Vorschau, Größe, Moderationsergebnis, Status und Upload-Zeit.</p><p><img src="'+r+'" alt="Erweiterte Filter" loading="lazy"></p><h2 id="betriebshinweise" tabindex="-1">Betriebshinweise <a class="header-anchor" href="#betriebshinweise" aria-label="Permalink to &quot;Betriebshinweise&quot;">​</a></h2><ul><li>Prüfe vor dem Sperren einer IP die hochgeladenen Dateien.</li><li>Suche und Sortierung helfen, neue, sehr aktive oder speicherintensive IPs zu finden.</li><li>IP-Standorte sind Schätzwerte. Nutze sie als Hinweis, nicht als Beweis.</li></ul><p><img src="'+d+'" alt="Mobile Ansicht" loading="lazy"></p>',30)])])}const _=s(h,[["render",p]]);export{z as __pageData,_ as default};
